mapper.sql:
( SELECT CONCAT('worklist-', q.id) AS id, q.id AS reference_id, 'WORKLIST' AS source, 'WORKLIST_SENT' AS type, 'info' AS severity, 'Patient sent to worklist' AS title, TRIM(CONCAT( COALESCE(, 'Patient'), CASE WHEN NULLIF(p.patient_uid, '') IS NOT NULL THEN CONCAT(' (', p.patient_uid, ')') ELSE '' END, ' was sent to ', COALESCE(NULLIF(m.name, ''), NULLIF(m.abbr, ''), 'a modality'), ' worklist', CASE WHEN NULLIF(q.visit_code, '') IS NOT NULL THEN CONCAT('. Visit ', q.visit_code) ELSE '' END, '.' )) AS message, 'Worklist' AS module, 'Assign Worklist' AS action, COALESCE(, 'System') AS username, COALESCE(, 'System') AS user_name, q.hospital_id, h.public_id::text AS hospital_public_key, h.name AS hospital_name, q.patient_id, p.public_id::text AS patient_public_key, AS patient_name, p.patient_uid, q.id AS worklist_id, q.public_id::text AS worklist_public_key, NULL::BIGINT AS study_id, NULL::TEXT AS study_public_key, q.visit_code, q.visit_code AS accession_number, COALESCE(NULLIF(m.name, ''), NULLIF(m.abbr, ''), '') AS modality_name, TO_CHAR(COALESCE(q.created_at, q.created), 'YYYY-MM-DD HH24:MI:SS') AS created_at, COALESCE(q.created_at, q.created) AS created_at_sort, '/worklist/worklist-list' AS endpoint, FALSE AS unread FROM pacs_worklists q INNER JOIN hospitals h ON h.id = q.hospital_id INNER JOIN patients p ON p.id = q.patient_id AND p.hospital_id = q.hospital_id LEFT JOIN modalities m ON m.id = q.modality_id LEFT JOIN users u ON u.id = q.created_by WHERE COALESCE(q.created_at, q.created) IS NOT NULL
AND q.hospital_id = #{hospitalId}
AND COALESCE(q.created_at, q.created) >= NOW() - (#{days} * INTERVAL '1 day')
UNION ALL
SELECT CONCAT('worklist-sent-', q.id) AS id, q.id AS reference_id, 'WORKLIST' AS source, 'WORKLIST_SEND_TO_PACS' AS type, 'success' AS severity, 'Worklist sent to PACS' AS title, TRIM(CONCAT( COALESCE(, 'Patient'), CASE WHEN NULLIF(p.patient_uid, '') IS NOT NULL THEN CONCAT(' (', p.patient_uid, ')') ELSE '' END, ' was sent to PACS', CASE WHEN NULLIF(q.visit_code, '') IS NOT NULL THEN CONCAT('. Visit ', q.visit_code) ELSE '' END, CASE WHEN NULLIF(machine.machine_ae_title, '') IS NOT NULL THEN CONCAT(' / ', machine.machine_ae_title) ELSE '' END, '.' )) AS message, 'Worklist' AS module, 'Send To PACS' AS action, COALESCE(, 'System') AS username, COALESCE(, 'System') AS user_name, q.hospital_id, h.public_id::text AS hospital_public_key, h.name AS hospital_name, q.patient_id, p.public_id::text AS patient_public_key, AS patient_name, p.patient_uid, q.id AS worklist_id, q.public_id::text AS worklist_public_key, NULL::BIGINT AS study_id, NULL::TEXT AS study_public_key, q.visit_code, q.visit_code AS accession_number, COALESCE(NULLIF(m.name, ''), NULLIF(m.abbr, ''), '') AS modality_name, TO_CHAR(q.sent_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at, q.sent_at AS created_at_sort, '/worklist/worklist-send-to-pacs' AS endpoint, FALSE AS unread FROM pacs_worklists q INNER JOIN hospitals h ON h.id = q.hospital_id INNER JOIN patients p ON p.id = q.patient_id AND p.hospital_id = q.hospital_id LEFT JOIN modalities m ON m.id = q.modality_id LEFT JOIN users u ON u.id = q.modified_by LEFT JOIN hospital_modality_server_routes r ON r.id = q.dicom_route_id AND r.hospital_id = q.hospital_id LEFT JOIN hospital_dicom_machines machine ON machine.id = r.machine_id AND machine.hospital_id = r.hospital_id WHERE q.sent_at IS NOT NULL
AND q.hospital_id = #{hospitalId}
AND q.sent_at >= NOW() - (#{days} * INTERVAL '1 day')
UNION ALL
SELECT CONCAT('study-', s.id) AS id, s.id AS reference_id, 'STUDY' AS source, 'IMAGE_RECEIVED' AS type, 'success' AS severity, 'Images received' AS title, TRIM(CONCAT( 'Images were received for ', COALESCE(, 'Patient'), CASE WHEN NULLIF(p.patient_uid, '') IS NOT NULL THEN CONCAT(' (', p.patient_uid, ')') ELSE '' END, CASE WHEN COALESCE(NULLIF(s.modality, ''), NULLIF(m.name, ''), NULLIF(m.abbr, '')) IS NOT NULL THEN CONCAT(' / ', COALESCE(NULLIF(s.modality, ''), NULLIF(m.name, ''), NULLIF(m.abbr, ''))) ELSE '' END, CASE WHEN NULLIF(s.accession_number, '') IS NOT NULL THEN CONCAT('. Accession ', s.accession_number) ELSE '' END, '.' )) AS message, 'Studies' AS module, 'Image Received' AS action, 'UDAYA_DICOM_SERVER' AS username, 'UDAYA_DICOM_SERVER' AS user_name, s.hospital_id, h.public_id::text AS hospital_public_key, h.name AS hospital_name, s.patient_id, p.public_id::text AS patient_public_key, AS patient_name, p.patient_uid, q.id AS worklist_id, q.public_id::text AS worklist_public_key, s.id AS study_id, s.public_id::text AS study_public_key, q.visit_code, s.accession_number, COALESCE(NULLIF(s.modality, ''), NULLIF(m.name, ''), NULLIF(m.abbr, ''), '') AS modality_name, TO_CHAR(COALESCE(s.received_at, s.created), 'YYYY-MM-DD HH24:MI:SS') AS created_at, COALESCE(s.received_at, s.created) AS created_at_sort, '/study/study-list' AS endpoint, FALSE AS unread FROM pacs_studies s INNER JOIN hospitals h ON h.id = s.hospital_id INNER JOIN patients p ON p.id = s.patient_id AND p.hospital_id = s.hospital_id LEFT JOIN pacs_worklist_study_links qsl ON qsl.hospital_id = s.hospital_id AND qsl.study_id = s.id AND qsl.is_primary = 1 LEFT JOIN pacs_worklists q ON q.id = qsl.worklist_id AND q.hospital_id = s.hospital_id LEFT JOIN modalities m ON m.id = q.modality_id WHERE s.is_active = 1 AND COALESCE(s.received_at, s.created) IS NOT NULL
AND s.hospital_id = #{hospitalId}
AND COALESCE(s.received_at, s.created) >= NOW() - (#{days} * INTERVAL '1 day')
) notifications
